import aiocoap

class CoAPServer(aiocoap.Resource):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.sensors = {
            "temp": 25.0,
            "humidity": 60.0
        }
        self.actuators = {
            "light": False
        }

    def render_get(self, request):
        path = request.path.split("/")
        if len(path) > 1:
            resource = path[1]
            if resource in self.sensors:
                return aiocoap.Content("Sensor value: {}".format(self.sensors[resource]))
            elif resource in self.actuators:
                return aiocoap.Content("Actuator value: {}".format(self.actuators[resource]))
        return aiocoap.Content("Invalid path")

    def render_put(self, request):
        path = request.path.split("/")
        if len(path) > 1:
            resource = path[1]
            if resource in self.actuators:
                value = request.payload.decode("utf-8")
                try:
                    self.actuators[resource] = bool(int(value))
                    return aiocoap.Content("Actuator value updated to {}".format(self.actuators[resource]))
                except ValueError:
                    return aiocoap.Content("Invalid value")
        return aiocoap.Content("Invalid path")

if __name__ == "__main__":
    server = CoAPServer()
    server.listen(("0.0.0.0", 5683))
    print("CoAP server started on port 5683")